package entities;

import java.time.LocalDateTime;
import java.util.ArrayList;
import java.util.List;

public class Musique {
    private Integer id;
    private String genre;
    private String audio;
    private LocalDateTime updatedAt;

    // Relation many-to-many via playlist_musique (loaded by service layer).
    private List<Playlist> playlists = new ArrayList<>();

    public Musique() {
    }

    public Integer getId() {
        return id;
    }

    public void setId(Integer id) {
        this.id = id;
    }

    public String getGenre() {
        return genre;
    }

    public void setGenre(String genre) {
        this.genre = genre;
    }

    public String getAudio() {
        return audio;
    }

    public void setAudio(String audio) {
        this.audio = audio;
    }

    public LocalDateTime getUpdatedAt() {
        return updatedAt;
    }

    public void setUpdatedAt(LocalDateTime updatedAt) {
        this.updatedAt = updatedAt;
    }

    public List<Playlist> getPlaylists() {
        return playlists;
    }

    public void setPlaylists(List<Playlist> playlists) {
        this.playlists = playlists != null ? playlists : new ArrayList<>();
    }
}

package entities;

import java.time.LocalDateTime;
import java.util.ArrayList;
import java.util.List;

public class Musique extends Oeuvre {
    private String genre;
    private String audio;
    private LocalDateTime updatedAt;

    // Relation many-to-many via playlist_musique (loaded by service layer).
    private List<Playlist> playlists = new ArrayList<>();

    public Musique() {
        super();
        setClasse("musique");
    }

    public String getGenre() {
        return genre;
    }

    public void setGenre(String genre) {
        this.genre = genre;
    }

    public String getAudio() {
        return audio;
    }

    public void setAudio(String audio) {
        this.audio = audio;
    }

    public LocalDateTime getUpdatedAt() {
        return updatedAt;
    }

    public void setUpdatedAt(LocalDateTime updatedAt) {
        this.updatedAt = updatedAt;
    }

    public List<Playlist> getPlaylists() {
        return playlists;
    }

    public void setPlaylists(List<Playlist> playlists) {
        this.playlists = playlists != null ? playlists : new ArrayList<>();
    }
}

package controllers;

import Services.UserService;
import entities.User;
import javafx.fxml.FXML;
import javafx.scene.control.Label;
import javafx.scene.control.PasswordField;
import javafx.scene.control.TextField;
import utils.InputValidator;

import java.sql.SQLDataException;

public class ConnexionController {

    @FXML
    private TextField emailField;

    @FXML
    private PasswordField passwordField;

    @FXML
    private Label messageLabel;

    private final UserService userService = new UserService();

    @FXML
    public void initialize() {
        emailField.textProperty().addListener((obs, oldV, newV) -> validateLiveInput());
        passwordField.textProperty().addListener((obs, oldV, newV) -> validateLiveInput());
    }

    @FXML
    private void onLogin() {
        clearMessage();

        String email = emailField.getText() == null ? "" : emailField.getText().trim();
        String password = passwordField.getText() == null ? "" : passwordField.getText();

        String localError = validateCredentials(email, password);
        if (localError != null) {
            setMessage(localError);
            return;
        }

        try {
            User user = userService.authenticate(email, password);
            String statut = user.getStatut() == null ? "" : user.getStatut().trim().toLowerCase();
            if ("bloqué".equals(statut) || "blocked".equals(statut)) {
                setMessage("Compte bloqué. Contactez l'administrateur.");
                return;
            }
            routeByRole(user);
        } catch (SQLDataException e) {
            setMessage(e.getMessage());
        }
    }

    @FXML
    private void onCreateAccount() {
        MainFX.switchToRegistrationView();
    }

    @FXML
    private void onBackToLanding() {
        MainFX.switchToAuthLandingView();
    }

    @FXML
    private void onForgotPassword() {
        MainFX.switchToForgotPasswordView();
    }

    private void routeByRole(User user) {
        String role = user.getRole() == null ? "" : user.getRole().trim().toLowerCase();
        switch (role) {
            case "amateur":
                MainFX.switchToAmateurView(user);
                break;
            case "artiste":
            case "artist":
                MainFX.switchToArtistView(user);
                break;
            case "admin":
                MainFX.switchToAdminView(user);
                break;
            default:
                setMessage("Rôle utilisateur non supporté : " + user.getRole());
        }
    }

    private void validateLiveInput() {
        String email = emailField.getText() == null ? "" : emailField.getText().trim();

        if (InputValidator.isBlank(email)) {
            clearMessage();
            return;
        }

        if (!InputValidator.isValidEmail(email)) {
            setMessage("Format d'e-mail invalide.");
            return;
        }

        clearMessage();
    }

    private String validateCredentials(String email, String password) {
        if (InputValidator.isBlank(email) || InputValidator.isBlank(password)) {
            return "Veuillez saisir votre e-mail et votre mot de passe.";
        }
        if (!InputValidator.isValidEmail(email)) {
            return "Format d'e-mail invalide.";
        }
        return null;
    }

    private void setMessage(String message) {
        messageLabel.setText(message);
        messageLabel.getStyleClass().removeAll("error", "success");
        messageLabel.getStyleClass().add("error");
    }

    private void clearMessage() {
        messageLabel.setText("");
        messageLabel.getStyleClass().removeAll("error", "success");
    }
}

package controllers;

import Services.UserService;
import entities.User;
import utils.SessionManager;
import javafx.fxml.FXML;
import javafx.scene.control.Label;
import javafx.scene.control.PasswordField;
import javafx.scene.control.TextField;
import utils.InputValidator;

import java.sql.SQLDataException;

public class ConnexionController {

    @FXML
    private TextField emailField;

    @FXML
    private PasswordField passwordField;

    @FXML
    private Label messageLabel;

    private final UserService userService = new UserService();

    @FXML
    public void initialize() {
        emailField.textProperty().addListener((obs, oldV, newV) -> validateLiveInput());
        passwordField.textProperty().addListener((obs, oldV, newV) -> validateLiveInput());
    }

    @FXML
    private void onLogin() {
        clearMessage();

        String email = emailField.getText() == null ? "" : emailField.getText().trim();
        String password = passwordField.getText() == null ? "" : passwordField.getText();

        String localError = validateCredentials(email, password);
        if (localError != null) {
            setMessage(localError);
            return;
        }

        try {
            User user = userService.authenticate(email, password);
            String statut = user.getStatut() == null ? "" : user.getStatut().trim().toLowerCase();
            if ("bloqué".equals(statut) || "blocked".equals(statut)) {
                setMessage("Compte bloqué. Contactez l'administrateur.");
                return;
            }
            // Sauvegarder la session persistante
            SessionManager.setCurrentUser(user);
            routeByRole(user);
        } catch (SQLDataException e) {
            setMessage(e.getMessage());
        }
    }

    @FXML
    private void onCreateAccount() {
        MainFX.switchToRegistrationView();
    }

    @FXML
    private void onBackToLanding() {
        MainFX.switchToAuthLandingView();
    }

    @FXML
    private void onForgotPassword() {
        MainFX.switchToForgotPasswordView();
    }

    private void routeByRole(User user) {
        String role = user.getRole() == null ? "" : user.getRole().trim().toLowerCase();
        switch (role) {
            case "amateur":
                MainFX.switchToAmateurView(user);
                break;
            case "artiste":
            case "artist":
                MainFX.switchToArtistView(user);
                break;
            case "admin":
                MainFX.switchToAdminView(user);
                break;
            default:
                setMessage("Rôle utilisateur non supporté : " + user.getRole());
        }
    }

    private void validateLiveInput() {
        String email = emailField.getText() == null ? "" : emailField.getText().trim();

        if (InputValidator.isBlank(email)) {
            clearMessage();
            return;
        }

        if (!InputValidator.isValidEmail(email)) {
            setMessage("Format d'e-mail invalide.");
            return;
        }

        clearMessage();
    }

    private String validateCredentials(String email, String password) {
        if (InputValidator.isBlank(email) || InputValidator.isBlank(password)) {
            return "Veuillez saisir votre e-mail et votre mot de passe.";
        }
        if (!InputValidator.isValidEmail(email)) {
            return "Format d'e-mail invalide.";
        }
        return null;
    }

    private void setMessage(String message) {
        messageLabel.setText(message);
        messageLabel.getStyleClass().removeAll("error", "success");
        messageLabel.getStyleClass().add("error");
    }

    private void clearMessage() {
        messageLabel.setText("");
        messageLabel.getStyleClass().removeAll("error", "success");
    }
}

package controllers;

import entities.User;
import javafx.application.Application;
import javafx.fxml.FXMLLoader;
import javafx.scene.Parent;
import javafx.scene.Scene;
import javafx.stage.Stage;

import java.io.IOException;
import java.net.URL;
import java.util.Objects;

public class MainFX extends Application {

    private static Stage primaryStage;
    private static User authenticatedUser;

    public static void switchToAuthLandingView() {
        authenticatedUser = null;
        switchScene("/views/auth/Landing.fxml", "/views/styles/auth.css", "Artium | Accueil");
    }

    public static void switchToLoginView() {
        authenticatedUser = null;
        switchScene("/views/auth/Connexion.fxml", "/views/styles/auth.css", "Artium | Connexion");
    }

    public static void switchToRegistrationView() {
        authenticatedUser = null;
        switchScene("/views/pages/inscription.fxml", "/views/styles/auth.css", "Artium | Inscription");
    }

    public static void switchToForgotPasswordView() {
        authenticatedUser = null;
        switchScene("/views/auth/ForgotPassword.fxml", "/views/styles/auth.css", "Artium | Mot de passe oublie");
    }

    public static void switchToArtistView() {
        authenticatedUser = null;
        switchScene("/views/artist/ArtistMain.fxml", "/views/styles/artist-theme.css", "Artist Dashboard");
    }

    public static void switchToArtistView(User user) {
        authenticatedUser = user;
        switchScene("/views/artist/ArtistMain.fxml", "/views/styles/artist-theme.css", "Artist Dashboard");
    }

    public static void switchToAdminView() {
        authenticatedUser = null;
        switchScene("/views/MainLayout.fxml", "/views/styles/dashboard.css", "Admin Dashboard");
    }

    public static void switchToAdminView(User user) {
        authenticatedUser = user;
        switchScene("/views/MainLayout.fxml", "/views/styles/dashboard.css", "Admin Dashboard");
    }

    public static void switchToAmateurView() {
        authenticatedUser = null;
        switchScene("/views/amateur/AmateurMain.fxml", "/views/styles/amateur-theme.css", "Amateur Dashboard");
    }

    public static void switchToAmateurView(User user) {
        authenticatedUser = user;
        switchScene("/views/amateur/AmateurMain.fxml", "/views/styles/amateur-theme.css", "Amateur Dashboard");
    }

    public static User getAuthenticatedUser() {
        return authenticatedUser;
    }

    private static void switchScene(String fxmlPath, String stylesheetPath, String title) {
        if (primaryStage == null) {
            return;
        }
        try {
            FXMLLoader loader = new FXMLLoader(MainFX.class.getResource(fxmlPath));
            Parent root = loader.load();
            Scene scene = new Scene(root);
            URL stylesheet = Objects.requireNonNull(MainFX.class.getResource(stylesheetPath), "Missing stylesheet");
            scene.getStylesheets().add(stylesheet.toExternalForm());
            primaryStage.setTitle(title);
            primaryStage.setScene(scene);
            primaryStage.show();
        } catch (IOException e) {
            throw new IllegalStateException("Failed to switch scene: " + fxmlPath, e);
        }
    }

    public void start(Stage stage) {
        primaryStage = stage;
        // Taille minimale globale pour garder le layout lisible, sans figer la taille des scenes.
        primaryStage.setMinWidth(1100);
        primaryStage.setMinHeight(650);
        switchToAuthLandingView();
    }

    public static void main(String[] args) {
        launch(args);
    }
}

package controllers;

import entities.User;
import utils.SessionManager;
import javafx.application.Application;
import javafx.fxml.FXMLLoader;
import javafx.scene.Parent;
import javafx.scene.Scene;
import javafx.stage.Stage;

import java.io.IOException;
import java.net.URL;
import java.util.Objects;

public class MainFX extends Application {

    private static Stage primaryStage;
    private static User authenticatedUser;

    public static void switchToAuthLandingView() {
        authenticatedUser = null;
        switchScene("/views/auth/Landing.fxml", "/views/styles/auth.css", "Artium | Accueil");
    }

    public static void switchToLoginView() {
        authenticatedUser = null;
        switchScene("/views/auth/Connexion.fxml", "/views/styles/auth.css", "Artium | Connexion");
    }

    public static void switchToRegistrationView() {
        authenticatedUser = null;
        switchScene("/views/pages/inscription.fxml", "/views/styles/auth.css", "Artium | Inscription");
    }

    public static void switchToForgotPasswordView() {
        authenticatedUser = null;
        switchScene("/views/auth/ForgotPassword.fxml", "/views/styles/auth.css", "Artium | Mot de passe oublie");
    }

    public static void switchToArtistView() {
        authenticatedUser = null;
        switchScene("/views/artist/ArtistMain.fxml", "/views/styles/artist-theme.css", "Artist Dashboard");
    }

    public static void switchToArtistView(User user) {
        authenticatedUser = user;
        switchScene("/views/artist/ArtistMain.fxml", "/views/styles/artist-theme.css", "Artist Dashboard");
    }

    public static void switchToAdminView() {
        authenticatedUser = null;
        switchScene("/views/MainLayout.fxml", "/views/styles/dashboard.css", "Admin Dashboard");
    }

    public static void switchToAdminView(User user) {
        authenticatedUser = user;
        switchScene("/views/MainLayout.fxml", "/views/styles/dashboard.css", "Admin Dashboard");
    }

    public static void switchToAmateurView() {
        authenticatedUser = null;
        switchScene("/views/amateur/AmateurMain.fxml", "/views/styles/amateur-theme.css", "Amateur Dashboard");
    }

    public static void switchToAmateurView(User user) {
        authenticatedUser = user;
        switchScene("/views/amateur/AmateurMain.fxml", "/views/styles/amateur-theme.css", "Amateur Dashboard");
    }

    public static User getAuthenticatedUser() {
        return authenticatedUser;
    }

    private static void switchScene(String fxmlPath, String stylesheetPath, String title) {
        if (primaryStage == null) {
            return;
        }
        try {
            FXMLLoader loader = new FXMLLoader(MainFX.class.getResource(fxmlPath));
            Parent root = loader.load();
            Scene scene = new Scene(root);
            URL stylesheet = Objects.requireNonNull(MainFX.class.getResource(stylesheetPath), "Missing stylesheet");
            scene.getStylesheets().add(stylesheet.toExternalForm());
            primaryStage.setTitle(title);
            primaryStage.setScene(scene);
            primaryStage.show();
        } catch (IOException e) {
            throw new IllegalStateException("Failed to switch scene: " + fxmlPath, e);
        }
    }

    public void start(Stage stage) {
        primaryStage = stage;
        // Taille minimale globale pour garder le layout lisible, sans figer la taille des scenes.
        primaryStage.setMinWidth(1100);
        primaryStage.setMinHeight(650);

        // Vérifier si une session persistante existe
        User sessionUser = SessionManager.getCurrentUser();
        if (sessionUser != null && sessionUser.getId() != null) {
            // Utilisateur connecté, rediriger vers le dashboard approprié
            authenticatedUser = sessionUser;
            redirectToUserDashboard(sessionUser);
        } else {
            // Aucune session, afficher la page d'accueil
            switchToAuthLandingView();
        }
    }

    private void redirectToUserDashboard(User user) {
        String role = user.getRole() == null ? "" : user.getRole().trim().toLowerCase();
        switch (role) {
            case "amateur":
                switchToAmateurView(user);
                break;
            case "artiste":
            case "artist":
                switchToArtistView(user);
                break;
            case "admin":
                switchToAdminView(user);
                break;
            default:
                switchToAuthLandingView();
        }
    }

    public static void main(String[] args) {
        launch(args);
    }
}

package controllers;

import entities.User;
import javafx.fxml.FXML;
import javafx.scene.control.Button;
import javafx.scene.control.MenuButton;
import javafx.scene.image.Image;
import javafx.scene.image.ImageView;
import javafx.scene.shape.Circle;

import java.io.File;

public class NavbarController {

    public interface ActionHandler {
        void onToggleSidebar();

        void onThemeSelected(boolean darkMode);
    }

    @FXML
    private Button notificationsButton;

    @FXML
    private MenuButton userMenuButton;

    private ActionHandler actionHandler;

    @FXML
    private ImageView navbarAvatarImageView;

    @FXML
    public void initialize() {
        installCircularClip();
    }

    public void setActionHandler(ActionHandler actionHandler) {
        this.actionHandler = actionHandler;
    }

    public void setUser(User user) {
        if (user == null || navbarAvatarImageView == null) {
            return;
        }

        String imagePath = pickProfileImage(user);
        if (imagePath != null) {
            try {
                Image image = new Image(toImageUrl(imagePath), 64, 64, false, true);
                if (!image.isError()) {
                    navbarAvatarImageView.setImage(image);
                    return;
                }
            } catch (IllegalArgumentException ex) {
                // Image invalide, garder l'image par defaut
            }
        }
    }

    private void installCircularClip() {
        Circle clip = new Circle(17);
        clip.setCenterX(17);
        clip.setCenterY(17);
        navbarAvatarImageView.setClip(clip);
    }

    private String pickProfileImage(User user) {
        if (user.getPhotoProfil() != null && !user.getPhotoProfil().trim().isEmpty()) {
            return user.getPhotoProfil().trim();
        }
        if (user.getPhotoReferencePath() != null && !user.getPhotoReferencePath().trim().isEmpty()) {
            return user.getPhotoReferencePath().trim();
        }
        return null;
    }

    private String toImageUrl(String imagePath) {
        if (imagePath.startsWith("file:") || imagePath.startsWith("http://") || imagePath.startsWith("https://")) {
            return imagePath;
        }
        return new File(imagePath).toURI().toString();
    }

    @FXML
    private void onSidebarToggle() {
        if (actionHandler != null) {
            actionHandler.onToggleSidebar();
        }
    }

    @FXML
    private void onThemeLight() {
        if (actionHandler != null) {
            actionHandler.onThemeSelected(false);
        }
    }

    @FXML
    private void onThemeDark() {
        if (actionHandler != null) {
            actionHandler.onThemeSelected(true);
        }
    }

    @FXML
    private void onNotificationsClick() {
        notificationsButton.setText("!!");
    }

    @FXML
    private void onProfileClick() {
        // Profil: point d'extension pour ouvrir une page profil admin.
    }

    @FXML
    private void onLogoutClick() {
        MainFX.switchToLoginView();
    }
}

